-- 20260605_seed_alchemy_codex_v3.sql
-- DNDNext alchemy codex v3 database seed.
-- Safe/idempotent: updates matching item_key/name rows and inserts missing rows.
-- Does not delete legacy rows. The website only surfaces canonical payload.alchemy rows.
-- Canonical rules in this seed:
--   * exactly three core ingredients per family at Common, Uncommon, Rare, and Very Rare
--   * unified bonuses.dieSteps attribute for healing, damage, ability buffs, and ability damage
--   * explicit payload.alchemy.bonuses are authoritative; no fallback bonuses are added to them

BEGIN;

WITH seed AS (
  SELECT * FROM jsonb_to_recordset($families$[{"key":"mushroom","label":"Mushroom","identity":"Major Effect source; moderate Duration and Extra Doses; exceptional mushrooms can grant a universal Die step.","examples":"Hearthcap Mushroom, Ghostcap Mushroom, Cloudcap Spore, Crowncap Polypore"},{"key":"root","label":"Root","identity":"Major Duration source; moderate Effect and Extra Doses; major natural source of the costly universal Die step.","examples":"Fieldroot, Red Hearthroot, Bloodsap Root, Titan Root"},{"key":"sap_resin","label":"Sap / Resin","identity":"Major Duration source; moderate Effect; supports extra batch output and lingering oils or salves.","examples":"Pine Pitch, Glassgum Resin, Mirrorgum, Kingsap Amber"},{"key":"moss_lichen","label":"Moss / Lichen","identity":"Major Duration source; moderate Effect, Area, and Extra Doses; tied to resistance and environmental adaptation.","examples":"Cavern Moss, Wardmoss, Sporeveil Moss, Dreamwatch Lichen"},{"key":"flower","label":"Flower","identity":"Major Save DC source; moderate Effect, Duration, and Area; tied to senses, charm, sleep, and clarity.","examples":"Field Bloom, Dreamlotus Bloom, Moonrose, Halo Lily"},{"key":"leaf_vine","label":"Leaf / Vine","identity":"Major Duration and mobility source; moderate Effect and Area; exceptional specimens can grant a universal Die step.","examples":"Greenleaf, Twinfrond, Windlace Vine, Worldvine Tendril"},{"key":"thorn_bark_wood","label":"Thorn / Bark / Wood","identity":"Major Effect source; moderate Duration and Save DC; tied to armor, physical reinforcement, and fortitude.","examples":"Oak Bark, Ironbark Strip, Kingshield Bark, Elder Ironwood Heart"},{"key":"mineral_salt_ash","label":"Mineral / Salt / Ash","identity":"Major Duration and Extra Doses source; moderate Effect and Save DC; tied to purification, binding, and resistance anchors.","examples":"Spring Salt, Glass Sand, Moonstone Powder, Eternity Salt"},{"key":"venom_poison","label":"Venom / Poison Plant","identity":"Major Effect and Save DC source; moderate Duration; major natural source of the costly universal Die step for harmful formulas.","examples":"Bitterleaf, Drowsevine, Longsting Root, Queen Asp Bloom"},{"key":"essence","label":"Essence","identity":"Fourth-slot type direction for elemental, radiant, necrotic, psychic, force, or poison effects.","examples":"Fire Essence, Frost Essence, Grave Essence, Force Shard"},{"key":"enhancer","label":"Enhancer / Catalyst","identity":"Fourth-slot technical upgrades such as universal Die steps, Extra Doses, Duration, Effect, or special Craft DC reduction.","examples":"Pure Catalyst, Distillation Agent, Binding Agent, Volatile Agent"},{"key":"holy_vital","label":"Holy / Vital Component","identity":"Fourth-slot restorative force and universal Die-step upgrades that apply before percentage bonuses.","examples":"Holy Component, Greater Holy Component"},{"key":"monster_fluid","label":"Bile / Gland / Monster Fluid","identity":"Fourth-slot monster biology, type direction, condition riders, mutation, Save DC, or universal Die-step twists.","examples":"Troll Blood, Wyvern Venom, Basilisk Bile, Dragon Gland"}]$families$::jsonb)
    AS x(key text, label text, identity text, examples text)
)
INSERT INTO public.alchemy_reagent_families(key, label, identity, examples, updated_at)
SELECT key, label, identity, examples, now() FROM seed
ON CONFLICT (key) DO UPDATE SET
  label=EXCLUDED.label,
  identity=EXCLUDED.identity,
  examples=EXCLUDED.examples,
  updated_at=now();

