    AS x(item_key text, item_name text, item_type text, item_rarity text, price_gp numeric, merchant_tags jsonb, payload jsonb)
), seed AS (
  SELECT item_key, item_name, item_type, item_rarity, price_gp,
    COALESCE(ARRAY(SELECT jsonb_array_elements_text(merchant_tags)), ARRAY[]::text[]) AS merchant_tags,
    payload
  FROM raw_seed
), updated AS (
  UPDATE public.items_catalog target
  SET item_name=seed.item_name,
      item_type=seed.item_type,
      item_rarity=seed.item_rarity,
      price_gp=seed.price_gp,
      merchant_tags=seed.merchant_tags,
      payload=seed.payload
  FROM seed
  WHERE target.item_key=seed.item_key
  RETURNING target.id, seed.item_key
)
INSERT INTO public.items_catalog(item_key,item_name,item_type,item_rarity,price_gp,merchant_tags,payload)
SELECT seed.item_key,seed.item_name,seed.item_type,seed.item_rarity,seed.price_gp,seed.merchant_tags,seed.payload
FROM seed
