y_notes":"Large clear crystals with slow silver currents moving inside. They never dissolve completely and smell of deep caverns, winter air, and distant lightning.","forage_dc":24,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Bitterleaf","rarity":"Common","effect":"Satisfies the family slot; no attribute bonus.","tags":["alchemy","reagent","venom_poison","venom-poison-plant","common","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":1,"effect_family":"venom_poison","positive_effects":["Satisfies the family slot","no attribute bonus."],"alchemy_notes":"A dark green leaf with black veins and an acrid herbal bite. It smells bitter enough to sting the nose.","forage_dc":10,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Stingnettle","rarity":"Common","effect":"Satisfies the family slot; no attribute bonus.","tags":["alchemy","reagent","venom_poison","venom-poison-plant","common","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":1,"effect_family":"venom_poison","positive_effects":["Satisfies the family slot","no attribute bonus."],"alchemy_notes":"A low dark nettle covered in nearly invisible glass hairs. Brushing it leaves a hot numbness, and it smells of pepper, green sap, and copper.","forage_dc":10,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Sourbell","rarity":"Common","effect":"Satisfies the family slot; no attribute bonus.","tags":["alchemy","reagent","venom_poison","venom-poison-plant","common","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":1,"effect_family":"venom_poison","positive_effects":["Satisfies the family slot","no attribute bonus."],"alchemy_notes":"A drooping yellow-green flower with a swollen bell full of cloudy nectar. It smells sharply of vinegar, citrus rind, and bruised weeds.","forage_dc":10,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Venomkiss Nettle","rarity":"Uncommon","effect":"Effect +50%","tags":["alchemy","reagent","venom_poison","venom-poison-plant","uncommon","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":2,"effect_family":"venom_poison","positive_effects":["Effect +50%"],"alchemy_notes":"A nettle with red hairs that twitch when warmed. It smells of crushed greens, pepper, and venom sacs.","forage_dc":14,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Widowshade","rarity":"Uncommon","effect":"Save DC +1","tags":["alchemy","reagent","venom_poison","venom-poison-plant","uncommon","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":2,"effect_family":"venom_poison","positive_effects":["Save DC +1"],"alchemy_notes":"A drooping purple-black sprig with glossy leaves. Its scent is sweet at first, then metallic and cold.","forage_dc":14,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Drowsevine","rarity":"Uncommon","effect":"Effect +25%; Duration +25%","tags":["alchemy","reagent","venom_poison","venom-poison-plant","uncommon","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":2,"effect_family":"venom_poison","positive_effects":["Effect +25%","Duration +25%"],"alchemy_notes":"A purple vine with soft fuzzy leaves that curl around warm objects. Its scent is sweet and heavy, like overripe berries and poppy smoke.","forage_dc":14,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Nightfang Cap","rarity":"Rare","effect":"Effect +25%; Save DC +1","tags":["alchemy","reagent","venom_poison","venom-poison-plant","rare","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":3,"effect_family":"venom_poison","positive_effects":["Effect +25%","Save DC +1"],"alchemy_notes":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal.","forage_dc":18,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Purple Ichor Bloom","rarity":"Rare","effect":"Effect +75%","tags":["alchemy","reagent","venom_poison","venom-poison-plant","rare","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":3,"effect_family":"venom_poison","positive_effects":["Effect +75%"],"alchemy_notes":"A bruised purple flower that seeps dark nectar. It smells sweet, rotten, and alchemically sharp.","forage_dc":18,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Longsting Root","rarity":"Rare","effect":"Effect +25%; Duration +50%","tags":["alchemy","reagent","venom_poison","venom-poison-plant","rare","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":3,"effect_family":"venom_poison","positive_effects":["Effect +25%","Duration +50%"],"alchemy_notes":"A narrow black root with a bright white core that numbs the knife used to cut it. It smells of licorice, wet iron, and bitter medicine.","forage_dc":18,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Black Lotus Venom","rarity":"Very Rare","effect":"Effect +100%","tags":["alchemy","reagent","venom_poison","venom-poison-plant","very-rare","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":4,"effect_family":"venom_poison","positive_effects":["Effect +100%"],"alchemy_notes":"A black lotus distillate in thick glossy drops. It smells floral, poisonous, and almost hypnotic.","forage_dc":24,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Wormwood Queen","rarity":"Very Rare","effect":"Effect +50%; Save DC +2","tags":["alchemy","reagent","venom_poison","venom-poison-plant","very-rare","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":4,"effect_family":"venom_poison","positive_effects":["Effect +50%","Save DC +2"],"alchemy_notes":"A tall silver-green wormwood crown with bitter pollen. It smells medicinal, royal, and dangerously clean.","forage_dc":24,"found_in":"DNDNext Alchemy Codex v3"},{"name":"Queen Asp Bloom","rarity":"Very Rare","effect":"Die step +1","tags":["alchemy","reagent","venom_poison","venom-poison-plant","very-rare","alchemy_codex_v2","alchemy_codex_v3"],"category":"Plant / Herb","reagent_family":"venom_poison","family_label":"Venom / Poison Plant","potency_rank":4,"effect_family":"venom_poison","positive_effects":["Die step +1"],"alchemy_notes":"A black-and-gold flower whose central petals resemble a coiled serpent. Its pollen prickles the skin and smells of jasmine, venom, and hot stone.","forage_dc":24,"found_in":"DNDNext Alchemy Codex v3"}]$plants$::jsonb)
    AS x(name text, rarity text, effect text, tags jsonb, category text, reagent_family text,
         family_label text, potency_rank integer, effect_family text, positive_effects jsonb,
         alchemy_notes text, forage_dc integer, found_in text)
), seed AS (
  SELECT name, rarity, effect,
    COALESCE(ARRAY(SELECT jsonb_array_elements_text(tags)), ARRAY[]::text[]) AS tags,
    category, reagent_family, family_label, potency_rank, effect_family,
    COALESCE(ARRAY(SELECT jsonb_array_elements_text(positive_effects)), ARRAY[]::text[]) AS positive_effects,
    alchemy_notes, forage_dc, found_in
  FROM raw_seed
), updated AS (
  UPDATE public.plants target
  SET rarity=seed.rarity,
      effect=seed.effect,
      tags=seed.tags,
      category=seed.category,
      reagent_family=seed.reagent_family,
      family_label=seed.family_label,
      potency_rank=seed.potency_rank,
      effect_family=seed.effect_family,
      positive_effects=seed.positive_effects,
      alchemy_notes=seed.alchemy_notes,
      forage_dc=seed.forage_dc,
      found_in=seed.found_in,
      updated_at=now()
  FROM seed
  WHERE lower(target.name)=lower(seed.name)
  RETURNING target.id, seed.name
)
INSERT INTO public.plants(name,rarity,effect,tags,category,reagent_family,family_label,potency_rank,effect_family,positive_effects,alchemy_notes,forage_dc,found_in,updated_at)
SELECT seed.name,seed.rarity,seed.effect,seed.tags,seed.category,seed.reagent_family,seed.family_label,seed.potency_rank,seed.effect_family,seed.positive_effects,seed.alchemy_notes,seed.forage_dc,seed.found_in,now()
FROM seed
WHERE NOT EXISTS (SELECT 1 FROM public.plants existing WHERE lower(existing.name)=lower(seed.name));

COMMIT;

